# apply-attach-v2-patch-b64.ps1
# Base64 인코딩 버전 — PowerShell이 스크립트 파일을 어떤 코드페이지로
# 읽어도(BOM 유무와 무관하게) 한글/이모지가 깨지지 않도록, 치환 대상
# 문자열을 전부 Base64(순수 ASCII)로 저장하고 실행 시점에 UTF-8로 복원한다.
# 지난 두 번의 시도(일반 here-string, BOM 추가)가 모두 같은 증상으로
# 실패했으므로, 인코딩 추측을 그만두고 이 방식으로 우회한다.

$ErrorActionPreference = 'Stop'
try { [Console]::OutputEncoding = [System.Text.Encoding]::UTF8 } catch {}

function _b64d($s) { [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($s)) }

$path = ".\webapp.html"
if (-not (Test-Path $path)) { throw "webapp.html을 찾을 수 없습니다 — 리포 루트에서 실행하세요." }

$encRead  = [System.Text.Encoding]::UTF8
$encWrite = New-Object System.Text.UTF8Encoding($true)
$content = [System.IO.File]::ReadAllText((Resolve-Path $path), $encRead)

$backupPath = ".\webapp.html.bak-$(Get-Date -Format yyyyMMdd-HHmmss)"
Copy-Item $path $backupPath
Write-Host "백업 생성: $backupPath"

$oldHtmlB64 = "PGlucHV0IHR5cGU9ImZpbGUiIGlkPSJhaS1wYW5lbC1maWxlLWlucHV0IiBzdHlsZT0iZGlzcGxheTpub25lIiBhY2NlcHQ9ImltYWdlLyosLnBkZiwudHh0LC5kb2N4IiBvbmNoYW5nZT0iaGFuZGxlRmlsZVNlbGVjdChldmVudCkiPg=="
$newHtmlB64 = "PGlucHV0IHR5cGU9ImZpbGUiIGlkPSJhaS1wYW5lbC1maWxlLWlucHV0IiBzdHlsZT0iZGlzcGxheTpub25lIiBhY2NlcHQ9ImltYWdlLyosLnBkZiwudHh0LC5kb2N4IiBtdWx0aXBsZSBvbmNoYW5nZT0iaGFuZGxlRmlsZVNlbGVjdChldmVudCkiPg=="
$oldHtmlAltB64 = "PGlucHV0IHR5cGU9ImZpbGUiIGlkPSJhaS1wYW5lbC1maWxlLWlucHV0IiBzdHlsZT0iZGlzcGxheTpub25lIiBhY2NlcHQ9ImltYWdlLyosLnBkZiwudHh0LC5kb2N4Ij4="
$newHtmlAltB64 = "PGlucHV0IHR5cGU9ImZpbGUiIGlkPSJhaS1wYW5lbC1maWxlLWlucHV0IiBzdHlsZT0iZGlzcGxheTpub25lIiBhY2NlcHQ9ImltYWdlLyosLnBkZiwudHh0LC5kb2N4IiBtdWx0aXBsZT4="
$oldJs1B64 = ""
$newJs1B64 = ""
$oldJs2B64 = ""
$newJs2B64 = ""
$oldJs3B64 = ""
$newJs3B64 = ""
$oldJs4B64 = ""
$newJs4B64 = ""

$oldHtml = _b64d $oldHtmlB64
$newHtml = _b64d $newHtmlB64
$oldHtmlAlt = _b64d $oldHtmlAltB64
$newHtmlAlt = _b64d $newHtmlAltB64
$oldJs1 = _b64d $oldJs1B64
$newJs1 = _b64d $newJs1B64
$oldJs2 = _b64d $oldJs2B64
$newJs2 = _b64d $newJs2B64
$oldJs3 = _b64d $oldJs3B64
$newJs3 = _b64d $newJs3B64
$oldJs4 = _b64d $oldJs4B64
$newJs4 = _b64d $newJs4B64

$replacements = @(
  @{ Name = '① HTML multiple 속성(onchange 있는 버전)'; Old = $oldHtml;  New = $newHtml;  Optional = $true },
  @{ Name = '① HTML multiple 속성(onchange 없는 버전)'; Old = $oldHtmlAlt; New = $newHtmlAlt; Optional = $true },
  @{ Name = '② _readAttachedFile → 헬퍼 세트';           Old = $oldJs1;   New = $newJs1 },
  @{ Name = '③ _clearAttachPreview';                     Old = $oldJs2;   New = $newJs2 },
  @{ Name = '④ _sendToAI';                                Old = $oldJs3;   New = $newJs3 },
  @{ Name = '⑤ userContent 조립부';                       Old = $oldJs4;   New = $newJs4 }
)

$applied = 0
foreach ($r in $replacements) {
  if ($content.Contains($r.Old)) {
    $content = $content.Replace($r.Old, $r.New)
    Write-Host "✅ $($r.Name) 치환 완료"
    $applied++
  } elseif ($r.Optional) {
    Write-Host "ℹ️  $($r.Name) — 해당 없음(정상, ①은 둘 중 하나만 맞으면 됨)"
  } else {
    Write-Warning "⚠️ $($r.Name) — 원본과 일치하는 블록을 못 찾았습니다."
  }
}

if ($applied -gt 0) {
  [System.IO.File]::WriteAllText((Resolve-Path $path), $content, $encWrite)
  Write-Host "`nwebapp.html 저장 완료 ($applied개 블록 치환됨)"
} else {
  Write-Host "`n치환된 블록이 없어 파일을 다시 쓰지 않았습니다."
}
Write-Host "`n변경 diff 확인: git diff webapp.html"
